#!/usr/bin/env python3
"""Single source of truth for the textbook structure.

Run this to (re)generate ../book.json, which both build.py and the
content-generation workflows consume. Each chapter carries a `scope` that
guides the writing agent, a `words` target, and an optional `model` hint
(opus for the most technically demanding chapters; sonnet otherwise).
"""
import json, os

# Each part: (dir, part_title, [chapters])
# Each chapter: dict(file, title, scope, words, model)
def ch(file, title, scope, words=4500, model="sonnet"):
    return dict(file=file, title=title, scope=scope, words=words, model=model)

