# The interview companion is a SEPARATE site, built from the same repo. Its part dir
# (and thus content path content/<dir>/...) is this; build.py outputs it flat under site/interview/.
INTERVIEW_DIR = "13-interview-prep"

INTERVIEW_META = {
    "title": "ML/LLM Interview Companion",
    "subtitle": "Prep for Top-Tier ML & LLM Engineering Interviews",
    "tagline": "A focused companion to The LLM Stack: frameworks, model answers, worked system-design cases, "
               "and a study plan for ML/LLM interview loops at big-tech and frontier labs.",
    "author": "Companion to The LLM Stack",
    "parent": {"title": "The LLM Stack", "href": "../index.html"},
}


def _emit(meta, parts, dest_name, here):
    out = {k: meta[k] for k in meta}
    out["parts"] = []
    nch = 0
    for pdir, ptitle, chapters in parts:
        chs = list(chapters) + EXTRA.get(pdir, [])
        out["parts"].append({"dir": pdir, "title": ptitle, "chapters": chs})
        nch += len(chs)
    dest = os.path.join(here, "..", dest_name)
    with open(dest, "w") as f:
        json.dump(out, f, indent=2)
    tot = sum(c["words"] for _, _, chs in parts for c in chs)
    opus = sum(1 for _, _, chs in parts for c in chs if c["model"] == "opus")
    print(f"Wrote {os.path.normpath(dest)}: {len(parts)} parts, {nch} chapters, "
          f"~{tot:,} target words (~{tot//300:,} pages); opus={opus}, sonnet={nch-opus}.")
    return nch


def main():
    here = os.path.dirname(os.path.abspath(__file__))
    book_parts = [p for p in BOOK["parts"] if p[0] != INTERVIEW_DIR]
    interview_parts = [p for p in BOOK["parts"] if p[0] == INTERVIEW_DIR]

    book_meta = {k: BOOK[k] for k in ("title", "subtitle", "tagline", "author")}
    _emit(book_meta, book_parts, "book.json", here)
    _emit(INTERVIEW_META, interview_parts, "interview.json", here)

if __name__ == "__main__":
    main()
